$ErrorActionPreference = 'SilentlyContinue'

$start = Get-Date
$log = 'C:\Users\KSR\Documents\Codex\2026-06-05\new-chat\work\occt_monitor.log'
$stopReason = $null

function Write-MonitorLog {
    param([string]$Message)
    $line = ('{0:u} {1}' -f (Get-Date), $Message)
    Add-Content -LiteralPath $log -Value $line
}

function Stop-Occt {
    param([string]$Reason)
    Write-MonitorLog "STOPPING OCCT: $Reason"
    Get-Process | Where-Object { $_.ProcessName -match '^OCCT$|^OcctMemtest$|^OCCT.*' } | Stop-Process -Force
}

Write-MonitorLog "Monitor started. StartTime=$($start.ToString('u'))"

while ($true) {
    $occt = Get-Process | Where-Object { $_.ProcessName -match '^OCCT$|^OcctMemtest$|^OCCT.*' }
    if (-not $occt) {
        Write-MonitorLog 'OCCT process no longer running. Monitor exiting.'
        break
    }

    $badSystemEvents = Get-WinEvent -FilterHashtable @{ LogName = 'System'; StartTime = $start } |
        Where-Object {
            ($_.ProviderName -match 'Microsoft-Windows-WHEA-Logger' -and $_.LevelDisplayName -in @('Error','Critical','Warning')) -or
            ($_.ProviderName -match 'nvlddmkm|Display|MemoryDiagnostics' -and $_.LevelDisplayName -in @('Error','Critical','Warning')) -or
            ($_.ProviderName -match 'Kernel-Power' -and $_.LevelDisplayName -in @('Error','Critical'))
        } |
        Select-Object -First 1

    if ($badSystemEvents) {
        $stopReason = "System event: $($badSystemEvents.ProviderName) $($badSystemEvents.Id) $($badSystemEvents.LevelDisplayName)"
        Stop-Occt $stopReason
        break
    }

    $badAppEvents = Get-WinEvent -FilterHashtable @{ LogName = 'Application'; StartTime = $start } |
        Where-Object {
            $_.LevelDisplayName -in @('Error','Critical') -and
            ($_.Message -match 'OCCT|OcctMemtest|memory|hardware')
        } |
        Select-Object -First 1

    if ($badAppEvents) {
        $stopReason = "Application event: $($badAppEvents.ProviderName) $($badAppEvents.Id) $($badAppEvents.LevelDisplayName)"
        Stop-Occt $stopReason
        break
    }

    $gpu = & nvidia-smi --query-gpu=temperature.gpu,power.draw,utilization.gpu,memory.used --format=csv,noheader,nounits 2>$null
    $mem = Get-CimInstance Win32_OperatingSystem | Select-Object -First 1 FreePhysicalMemory,TotalVisibleMemorySize
    $occtSummary = ($occt | ForEach-Object { "$($_.ProcessName):$($_.Id)" }) -join ','
    Write-MonitorLog "OK OCCT=[$occtSummary] GPU=[$gpu] FreeMemMB=$([math]::Round($mem.FreePhysicalMemory/1024))"

    Start-Sleep -Seconds 60
}

if ($stopReason) {
    Write-MonitorLog "Monitor exited after stop. Reason=$stopReason"
} else {
    Write-MonitorLog 'Monitor exited normally.'
}

$ErrorActionPreference = 'SilentlyContinue'

$started = Get-Date
$root = 'C:\Users\KSR\Documents\Codex\2026-06-05\new-chat\work'
$log = Join-Path $root 'overnight_stability_supervisor.log'
$summary = Join-Path $root 'overnight_stability_summary.txt'

function Log {
    param([string]$Message)
    $line = ('{0:u} {1}' -f (Get-Date), $Message)
    Add-Content -LiteralPath $log -Value $line
}

function Snapshot {
    param([string]$Label)
    Log "SNAPSHOT: $Label"
    try {
        $mem = Get-CimInstance Win32_OperatingSystem | Select-Object -First 1 FreePhysicalMemory,TotalVisibleMemorySize,LastBootUpTime
        Log ("MEM FreeMB={0} TotalMB={1} Boot={2}" -f [math]::Round($mem.FreePhysicalMemory / 1024), [math]::Round($mem.TotalVisibleMemorySize / 1024), $mem.LastBootUpTime)
    } catch {}
    try {
        $gpu = & nvidia-smi --query-gpu=temperature.gpu,power.draw,utilization.gpu,memory.used --format=csv,noheader,nounits 2>$null
        Log "GPU $gpu"
    } catch {}
    try {
        $procs = Get-Process | Where-Object { $_.ProcessName -match 'OCCT|OcctMemtest|Cinebench|3DMark' } |
            ForEach-Object { "$($_.ProcessName):$($_.Id):CPU=$([math]::Round($_.CPU,1)):WSMB=$([math]::Round($_.WorkingSet64/1MB))" }
        Log ("PROCS " + ($procs -join ', '))
    } catch {}
}

function Get-BadEvent {
    param([datetime]$Since)
    try {
        $systemEvent = Get-WinEvent -FilterHashtable @{ LogName = 'System'; StartTime = $Since } |
            Where-Object {
                ($_.ProviderName -match 'Microsoft-Windows-WHEA-Logger' -and $_.LevelDisplayName -in @('Error','Critical','Warning')) -or
                ($_.ProviderName -match 'nvlddmkm|Display|MemoryDiagnostics' -and $_.LevelDisplayName -in @('Error','Critical','Warning')) -or
                ($_.ProviderName -match 'Kernel-Power' -and $_.LevelDisplayName -in @('Error','Critical'))
            } |
            Select-Object -First 1
        if ($systemEvent) { return "System event: $($systemEvent.ProviderName) Id=$($systemEvent.Id) Level=$($systemEvent.LevelDisplayName)" }
    } catch {}

    try {
        $appEvent = Get-WinEvent -FilterHashtable @{ LogName = 'Application'; StartTime = $Since } |
            Where-Object {
                $_.LevelDisplayName -in @('Error','Critical') -and
                ($_.Message -match 'OCCT|OcctMemtest|Cinebench|3DMark|hardware|memory')
            } |
            Select-Object -First 1
        if ($appEvent) { return "Application event: $($appEvent.ProviderName) Id=$($appEvent.Id) Level=$($appEvent.LevelDisplayName)" }
    } catch {}

    return $null
}

function Stop-Tests {
    param([string]$Reason)
    Log "STOP TESTS: $Reason"
    Get-Process | Where-Object { $_.ProcessName -match '^OCCT$|^OcctMemtest$|^Cinebench$|^3DMark' } | Stop-Process -Force
}

function Finish-And-Shutdown {
    param([string]$Status)
    Snapshot "final"
    $events = Get-BadEvent -Since $started
    @(
        "Status: $Status"
        "Started: $($started.ToString('u'))"
        "Finished: $((Get-Date).ToString('u'))"
        "BadEvent: $events"
        "Log: $log"
    ) | Set-Content -LiteralPath $summary
    Log "SUMMARY WRITTEN: $summary"
    Log "SHUTDOWN REQUESTED"
    shutdown /s /t 60 /c "Stability test supervisor finished. See overnight_stability_summary.txt"
}

function Invoke-CpuStress {
    param([int]$Minutes = 30)
    Log "CPU stress started for $Minutes minutes."
    $deadline = (Get-Date).AddMinutes($Minutes)
    $jobs = @()
    $threads = [Environment]::ProcessorCount
    for ($i = 0; $i -lt $threads; $i++) {
        $jobs += Start-Job -ScriptBlock {
            param($untilTicks)
            $x = 0.000001
            while ([DateTime]::UtcNow.Ticks -lt $untilTicks) {
                for ($j = 0; $j -lt 50000; $j++) {
                    $x = [Math]::Sqrt($x + 1.000001)
                    if ($x -gt 1000000) { $x = 0.000001 }
                }
            }
            $x
        } -ArgumentList $deadline.ToUniversalTime().Ticks
    }

    while ((Get-Date) -lt $deadline) {
        $bad = Get-BadEvent -Since $started
        if ($bad) {
            Log "BAD EVENT DURING CPU STRESS: $bad"
            $jobs | Stop-Job
            $jobs | Remove-Job -Force
            Stop-Tests $bad
            Finish-And-Shutdown "FAILED: $bad"
            exit
        }
        Snapshot "cpu-stress"
        Start-Sleep -Seconds 60
    }

    $jobs | Wait-Job | Out-Null
    $jobs | Remove-Job -Force
    Log "CPU stress completed."
}

Log "Overnight supervisor started."
Snapshot "initial"

while ($true) {
    $bad = Get-BadEvent -Since $started
    if ($bad) {
        Log "BAD EVENT DURING OCCT MEMORY: $bad"
        Stop-Tests $bad
        Finish-And-Shutdown "FAILED: $bad"
        exit
    }

    $occtMem = Get-Process -Name 'OcctMemtest' -ErrorAction SilentlyContinue
    $occt = Get-Process -Name 'OCCT' -ErrorAction SilentlyContinue
    if (-not $occtMem) {
        Log "OcctMemtest no longer running."
        break
    }

    Snapshot "occt-memory"
    Start-Sleep -Seconds 60
}

Start-Sleep -Seconds 20
$badAfterMemory = Get-BadEvent -Since $started
if ($badAfterMemory) {
    Stop-Tests $badAfterMemory
    Finish-And-Shutdown "FAILED after memory test: $badAfterMemory"
    exit
}

Log "OCCT Memory appears completed without monitored hardware errors."

Invoke-CpuStress -Minutes 30

$badFinal = Get-BadEvent -Since $started
if ($badFinal) {
    Stop-Tests $badFinal
    Finish-And-Shutdown "FAILED: $badFinal"
    exit
}

Finish-And-Shutdown "PASSED: OCCT Memory completed and CPU stress completed without monitored hardware errors."
